import React, { useState } from 'react';
import { useApp } from '../context/AppContext';

export default function LeaveRequests() {
  const { leaveRequests, updateLeaveStatus, acceptSubstitute, currentUser } = useApp();
  const [expanded, setExpanded] = useState(null);
  const [filter, setFilter] = useState('all');

  const isAdmin = currentUser.role === 's';

  // ✅ Filtered requests
  const filteredRequests = leaveRequests
    .filter(req => {
      if (isAdmin) return filter === 'all' || req.status === filter;

      if (currentUser.role === 'staff') {
        const isAssigned = req.substituteRequests?.some(sub =>
          sub.freeTeachers?.some(t => String(t.id) === String(currentUser.id))
        );
        return isAssigned && (filter === 'all' || req.status === filter);
      }

      // Applicant
      return req.requesterId === currentUser.id &&
             (filter === 'all' || req.status === filter);
    })
    .sort((a, b) => b.id - a.id);

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>📋 Leave Requests</h1>

      {/* Filter Tabs */}
      <div style={styles.tabs}>
        {['all', 'pending', 'approved', 'rejected'].map(f => (
          <button
            key={f}
            onClick={() => setFilter(f)}
            style={{ ...styles.tab, ...(filter === f ? styles.tabActive : {}) }}
          >
            {f === 'all' ? '📋 All' : f === 'pending' ? '⏳ Pending' : f === 'approved' ? '✅ Approved' : '❌ Rejected'}
            <span style={styles.count}>
              {leaveRequests.filter(r => f === 'all' || r.status === f).length}
            </span>
          </button>
        ))}
      </div>

      {/* Request Cards */}
      <div style={styles.list}>
        {filteredRequests.length === 0 && <div style={styles.empty}>No leave requests found</div>}
        {filteredRequests.map(req => (
          <div key={req.id} style={styles.card}>
            <div style={styles.cardHeader}>
              <div style={styles.leftInfo}>
                <div style={styles.avatar}>{req.teacherName[0]}</div>
                <div>
                  <div style={styles.teacherName}>{req.teacherName}</div>
                  <div style={styles.dates}>📅 {req.fromDate} → {req.toDate}</div>
                  <div style={styles.reason}>📝 {req.reason}</div>
                  <div style={styles.meta}>
                    Applied: {req.createdAt} | {req.substituteRequests.length} class(es)
                  </div>
                  {/* Show who requested if staff viewing */}
                  {currentUser.role === 'staff' && !isAdmin && (
                    <div style={styles.meta}>Requested by: {req.teacherName}</div>
                  )}
                </div>
              </div>

              <div style={styles.rightActions}>
                <StatusBadge status={req.status} />

                {/* Approve / Reject for admin or free staff */}
                {req.status === 'pending' && (
                  <div style={styles.actionBtns}>
                    {(isAdmin || req.substituteRequests.some(sub => sub.freeTeachers.some(t => t.id === currentUser.id))) && (
                      <>
                        <button style={styles.approveBtn} onClick={() => updateLeaveStatus(req.id, 'approved')}>
                          ✅ Approve
                        </button>
                        <button style={styles.rejectBtn} onClick={() => updateLeaveStatus(req.id, 'rejected')}>
                          ❌ Reject
                        </button>
                      </>
                    )}
                  </div>
                )}

                {req.substituteRequests.length > 0 && (
                  <button style={styles.detailBtn} onClick={() => setExpanded(expanded === req.id ? null : req.id)}>
                    {expanded === req.id ? '▲ Hide' : '▼ Show'} Substitutes
                  </button>
                )}
              </div>
            </div>

            {/* Substitute Section */}
            {expanded === req.id && (
              <div style={styles.subSection}>
                <h3 style={styles.subTitle}>🔄 Substitute Assignments</h3>
                <table style={styles.table}>
                  <thead>
                    <tr>
                      {['Date', 'Day', 'Period', 'Time', 'Class', 'Substitute Teacher'].map(h => (
                        <th key={h} style={styles.th}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {req.substituteRequests.map((sub, idx) => (
                      <tr key={idx} style={styles.tr}>
                        <td style={styles.td}>{sub.date}</td>
                        <td style={styles.td}>{sub.day}</td>
                        <td style={styles.td}><span style={styles.periodBadge}>P{sub.period}</span></td>
                        <td style={styles.td}>{sub.time}</td>
                        <td style={styles.td}><strong>{sub.class}</strong></td>
                        <td style={styles.td}>
                          {sub.assignedTeacherId ? (
                            <span style={styles.assigned}>
                              ✔ Accepted by {req.substituteRequests[idx].acceptedByName}
                            </span>
                          ) : sub.freeTeachers.some(t => t.id === currentUser.id) ? (
                            <button style={styles.acceptBtn} onClick={() => acceptSubstitute(req.id, idx, currentUser.id)}>
                              Accept
                            </button>
                          ) : (
                            <span style={styles.waiting}>Waiting for teacher</span>
                          )}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}

// Status Badge
function StatusBadge({ status }) {
  const map = {
    pending: { bg: '#fef3c7', color: '#92400e', label: '⏳ Pending' },
    approved: { bg: '#d1fae5', color: '#065f46', label: '✅ Approved' },
    rejected: { bg: '#fee2e2', color: '#991b1b', label: '❌ Rejected' },
  };
  const s = map[status] || map.pending;
  return (
    <span style={{ background: s.bg, color: s.color, padding: '6px 16px', borderRadius: 20, fontSize: 13, fontWeight: 700 }}>
      {s.label}
    </span>
  );
}


// Styles for LeaveRequests
const styles = {
  container: { padding: 32, maxWidth: 1100, margin: '0 auto' },
  title: { fontSize: 28, fontWeight: 800, color: '#1e293b', marginBottom: 24 },
  tabs: { display: 'flex', gap: 8, marginBottom: 24 },
